#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=1005;
int n,k,x[N],y[N],f[N];
struct node
{
	int u,v;
	double dis;
	bool operator<(const node other)  const
	{
		return dis<other.dis;
	}
};
vector<node> v;
int find(int x)
{
	if(f[x]==x) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>k;
	for(int i=1;i<=n;i++)
	{
		cin>>x[i]>>y[i];
		f[i]=i;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=i+1;j<=n;j++)
		{
			double diss=sqrt(abs(x[i]-x[j])*abs(x[i]-x[j])+abs(y[i]-y[j])*abs(y[i]-y[j]));
			v.push_back(node{i,j,diss});
		}
	}
	sort(v.begin(),v.end());
	for(int i=0;i<v.size();i++)
	{
		int u=v[i].u,vv=v[i].v;
		double w=v[i].dis;
		int fu=find(u),fv=find(vv);
		if(fu==fv) continue;
		if(n==k)
		{
			cout<<fixed<<setprecision(2)<<w;
			return 0;
		}
		n--;
		f[fu]=fv;
	}
	return 0;
}
